  /* ── Global overrides (beat inline styles via !important) ── */
  body.mh-dark, body.mh-dark #root { background:var(--bg)!important; color:var(--text)!important; }
  body.mh-dark * { color:inherit; border-color:var(--border); }

  /* Surfaces */
