// ── History ───────────────────────────────────────────────────────────────────
function History({ t }) {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    api.get('/api/history')
      .then(r => { setHistory(r.data); setLoading(false); })
      .catch(() => { setError('Could not load history. Run migrate_db.py if you haven\'t yet, then restart Flask.'); setLoading(false); });
  }, []);

  const exportData = async (fmt) => {
    setExporting(true);
    try {
      const res = await api.get(`/api/export/history?format=${fmt}`, { responseType: 'blob' });
      const url = URL.createObjectURL(res.data);
      const a = document.createElement('a');
      a.href = url; a.download = `medihelp_history.${fmt}`;
      a.click(); URL.revokeObjectURL(url);
    } catch { alert('Export failed. Is the backend running?'); }
    setExporting(false);
  };

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;
  if (error)   return <div className="alert alert-warning"><I c="fa-triangle-exclamation" style={{marginRight:8}}/>{error}</div>;

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',flexWrap:'wrap',gap:8}}>
        <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,color:'#374151',display:'flex',alignItems:'center',gap:8}}>
          <I c="fa-clock-rotate-left" style={{color:'#16a34a'}}/>{t.history} ({history.length})
        </h3>
        {history.length > 0 && (
          <div style={{display:'flex',gap:6}}>
            <button className="btn btn-ghost btn-sm" onClick={()=>exportData('csv')} disabled={exporting}>
              <I c="fa-file-csv" style={{marginRight:4}}/>CSV
            </button>
            <button className="btn btn-ghost btn-sm" onClick={()=>exportData('json')} disabled={exporting}>
              <I c="fa-file-code" style={{marginRight:4}}/>JSON
            </button>
          </div>
        )}
      </div>

      {!history.length ? (
        <div style={{textAlign:'center',padding:'3rem',color:'#6b7280'}}>
          <I c="fa-clipboard-list" style={{fontSize:'3rem',marginBottom:12,display:'block',color:'#d1d5db'}}/>
          <p>{t.noHistory}</p>
        </div>
      ) : history.map(h => (
        <HistoryItem key={h.id} h={h} t={t}/>
      ))}
    </div>
  );
}

// ── Hospital Map ──────────────────────────────────────────────────────────────
function HospitalMap() {
  const [hospitals, setHospitals]   = useState([]);
  const [loading, setLoading]       = useState(false);
  const [error, setError]           = useState('');
  const [search, setSearch]         = useState('');
  const [selected, setSelected]     = useState(null);
  const [userLocation, setUserLocation] = useState(null);
  const [locating, setLocating]     = useState(false);
  const [mapCenter, setMapCenter]   = useState(null);
  const [mode, setMode]             = useState('none'); // 'search' | 'nearby' | 'none'

  // Use Overpass API (unlimited Kenyan hospitals from OpenStreetMap)
  const fetchOverpass = useCallback((lat, lon, q) => {
    setLoading(true); setError('');
    const params = new URLSearchParams();
    if (lat != null) { params.set('lat', lat); params.set('lon', lon); params.set('radius', 30000); }
    if (q) params.set('q', q);
    api.get(`/api/hospitals/overpass?${params}`)
      .then(r => {
        if (r.data.error) { setError(r.data.error); setLoading(false); return; }
        setHospitals(r.data);
        setLoading(false);
      })
      .catch(() => {
        // fallback to local DB if Overpass unavailable
        api.get(`/api/hospitals${q?`?q=${encodeURIComponent(q)}`:lat?`?lat=${lat}&lon=${lon}`:''}`)
          .then(r => { setHospitals(r.data); setLoading(false); })
          .catch(() => { setError('Could not load hospitals. Check your internet connection.'); setLoading(false); });
      });
  }, []);

  const doSearch = () => {
    if (!search.trim()) { setError('Enter a hospital name or location to search.'); return; }
    setMode('search');
    fetchOverpass(null, null, search.trim());
  };

  const getLocation = () => {
    if (!navigator.geolocation) { alert('Geolocation not supported by your browser.'); return; }
    setLocating(true); setError('');
    navigator.geolocation.getCurrentPosition(
      pos => {
        const { latitude: lat, longitude: lon } = pos.coords;
        setUserLocation({ lat, lon }); setMapCenter([lat, lon]); setLocating(false);
        setMode('nearby');
        fetchOverpass(lat, lon, '');
      },
      () => { setError('Could not get your location. Please allow location access.'); setLocating(false); }
    );
  };

  const hospitalIcon = L.divIcon({
    html:`<div style="background:#16a34a;width:30px;height:30px;border-radius:50%;border:2.5px solid white;box-shadow:0 2px 8px rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;color:white;font-size:13px"><i class='fa-solid fa-hospital-user'></i></div>`,
    className:'', iconSize:[30,30], iconAnchor:[15,15]
  });
  const userIcon = L.divIcon({
    html:`<div style="background:#0891b2;width:28px;height:28px;border-radius:50%;border:2.5px solid white;box-shadow:0 2px 8px rgba(0,0,0,0.3);display:flex;align-items:center;justify-content:center;color:white;font-size:12px"><i class='fa-solid fa-location-crosshairs'></i></div>`,
    className:'', iconSize:[28,28], iconAnchor:[14,14]
  });

  return (
    <div>
      <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,marginBottom:'0.5rem',display:'flex',alignItems:'center',gap:8}}>
        <I c="fa-hospital" style={{color:'#16a34a'}}/>Healthcare Facilities
        <span style={{fontWeight:400,fontSize:'0.75rem',color:'#6b7280',marginLeft:4}}>— All Kenya (via OpenStreetMap)</span>
      </h3>
      <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:'0.75rem'}}>
        <I c="fa-circle-info" style={{marginRight:5,color:'#0891b2'}}/>
        Search any hospital by name, or use <strong>Near Me</strong> to find facilities within 30 km of your location.
      </div>
      <div style={{display:'flex',gap:8,marginBottom:'1rem',flexWrap:'wrap'}}>
        <div style={{position:'relative',flex:1,minWidth:200}}>
          <I c="fa-magnifying-glass" style={{position:'absolute',left:10,top:'50%',transform:'translateY(-50%)',color:'#9ca3af',fontSize:'0.85rem'}}/>
          <input className="form-input" value={search} onChange={e=>setSearch(e.target.value)}
            onKeyDown={e=>e.key==='Enter'&&doSearch()}
            placeholder="e.g. Kenyatta National, Aga Khan, Nairobi Hospital..."
            style={{paddingLeft:34}}/>
        </div>
        <button className="btn btn-outline" onClick={doSearch} disabled={loading}>
          <I c="fa-magnifying-glass" style={{marginRight:6}}/>Search
        </button>
        <button className="btn btn-primary" onClick={getLocation} disabled={locating||loading}>
          {locating ? <><span className="spinner" style={{width:14,height:14}}/> Locating…</> : <><I c="fa-location-crosshairs" style={{marginRight:6}}/>Near Me</>}
        </button>
      </div>

      {error && <div className="alert alert-warning" style={{marginBottom:'0.75rem'}}><I c="fa-triangle-exclamation" style={{marginRight:8}}/>{error}</div>}

      {/* Map */}
      <div style={{borderRadius:12,overflow:'hidden',border:'1px solid #e5e7eb',marginBottom:'1rem'}}>
        <MapContainer center={userLocation?[userLocation.lat,userLocation.lon]:[-1.2921,36.8219]} zoom={userLocation?11:6} style={{height:380}}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution='&copy; OpenStreetMap contributors'/>
          {mapCenter && <FlyTo coords={mapCenter}/>}
          {userLocation && <Marker position={[userLocation.lat,userLocation.lon]} icon={userIcon}><Popup><strong>Your Location</strong></Popup></Marker>}
          {hospitals.map(h => (
            <Marker key={h.id} position={[h.latitude,h.longitude]} icon={hospitalIcon} eventHandlers={{click:()=>setSelected(h)}}>
              <Popup>
                <strong style={{color:'#16a34a'}}>{h.name}</strong><br/>
                {h.address && <>{h.address}<br/></>}
                {h.phone && <><I c="fa-phone" style={{marginRight:4}}/>{h.phone}<br/></>}
                {h.distance_km!=null && <><I c="fa-route" style={{marginRight:4}}/>{h.distance_km} km away<br/></>}
                {h.emergency ? <span style={{color:'#dc2626',fontWeight:700}}>24hr Emergency</span> : null}
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* Prompt when nothing searched yet */}
      {mode === 'none' && !loading && (
        <div style={{textAlign:'center',padding:'2rem',color:'#9ca3af'}}>
          <I c="fa-hospital" style={{fontSize:'2.5rem',display:'block',marginBottom:10,color:'#d1d5db'}}/>
          <p style={{fontSize:'0.875rem'}}>Search for a hospital by name, or tap <strong>Near Me</strong> to see hospitals near you.</p>
        </div>
      )}

      {/* Loading */}
      {loading && <div style={{textAlign:'center',padding:'2rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/><p style={{marginTop:10,fontSize:'0.8rem',color:'#6b7280'}}>Searching OpenStreetMap…</p></div>}

      {/* Results */}
      {!loading && hospitals.length > 0 && (
        <>
          <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:8}}>
            <I c="fa-list" style={{marginRight:5}}/>{hospitals.length} hospital{hospitals.length!==1?'s':''} found
          </div>
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(260px,1fr))',gap:10}}>
            {hospitals.map(h => (
              <div key={h.id} className="card hospital-list-item"
                onClick={()=>{setSelected(selected?.id===h.id?null:h); if(h.latitude&&h.longitude) setMapCenter([h.latitude,h.longitude]);}}
                style={{cursor:'pointer',border:selected?.id===h.id?'2px solid #16a34a':'',padding:'0.9rem'}}>
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:5}}>
                  <div style={{fontWeight:700,fontSize:'0.875rem',flex:1}}>{h.name}</div>
                  <div style={{display:'flex',gap:4,flexShrink:0,marginLeft:8}}>
                    {h.emergency ? <span style={{background:'#fef2f2',color:'#dc2626',borderRadius:6,padding:'1px 6px',fontSize:'0.65rem',fontWeight:700}}>24h</span> : null}
                  </div>
                </div>
                {h.address && <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:3}}><I c="fa-location-dot" style={{color:'#16a34a',marginRight:4}}/>{h.address}</div>}
                {h.phone && <div style={{fontSize:'0.78rem',color:'#16a34a',fontWeight:600,marginBottom:4}}><I c="fa-phone" style={{marginRight:4}}/>{h.phone}</div>}
                {h.distance_km!=null && <div style={{fontSize:'0.75rem',color:'#0891b2',fontWeight:700}}><I c="fa-route" style={{marginRight:4}}/>{h.distance_km} km away</div>}
              </div>
            ))}
          </div>
        </>
      )}

      {!loading && mode!=='none' && hospitals.length===0 && !error && (
        <div style={{textAlign:'center',padding:'1.5rem',color:'#6b7280',fontSize:'0.875rem'}}>
          No hospitals found. Try a different name or expand your search area.
        </div>
      )}
    </div>
  );
}

// ── Appointments ──────────────────────────────────────────────────────────────
function AppointmentsTab({ t }) {
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editId, setEditId] = useState(null);
  const [form, setForm] = useState({ doctor_name:'', hospital_name:'', appointment_date:'', appointment_time:'', notes:'' });
  const [msg, setMsg] = useState('');

  const load = useCallback(() => {
    setLoading(true);
    api.get('/api/appointments')
      .then(a => { setAppointments(a.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);
  useEffect(() => { load(); }, [load]);

  const set = k => e => setForm({ ...form, [k]: e.target.value });

  const handleSubmit = async () => {
    if (!form.doctor_name || !form.appointment_date || !form.appointment_time) {
      setMsg('Please fill doctor name, date, and time.'); return;
    }
    setSaving(true); setMsg('');
    try {
      if (editId) {
        await api.put(`/api/appointments/${editId}`, form);
      } else {
        await api.post('/api/appointments', form);
      }
      setShowForm(false); setEditId(null); setForm({ doctor_name:'', hospital_name:'', appointment_date:'', appointment_time:'', notes:'' });
      load();
    } catch { setMsg('Failed to save. Is the backend running?'); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this appointment?')) return;
    await api.delete(`/api/appointments/${id}`);
    load();
  };

  const startEdit = (a) => {
    setForm({ doctor_name:a.doctor_name, hospital_name:a.hospital_name||'', appointment_date:a.appointment_date, appointment_time:a.appointment_time, notes:a.notes||'' });
    setEditId(a.id); setShowForm(true);
  };

  const updateStatus = async (id, status) => {
    await api.put(`/api/appointments/${id}`, { status });
    load();
  };

  const statusColor = { scheduled:'#0891b2', completed:'#16a34a', cancelled:'#dc2626' };

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',flexWrap:'wrap',gap:8}}>
        <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,color:'#374151',display:'flex',alignItems:'center',gap:8}}>
          <I c="fa-calendar-check" style={{color:'#16a34a'}}/>{t.appointments} ({appointments.length})
        </h3>
        <button className="btn btn-primary btn-sm" onClick={()=>{setShowForm(!showForm);setEditId(null);setForm({doctor_name:'',hospital_name:'',appointment_date:'',appointment_time:'',notes:''});}}>
          <I c={showForm?'fa-xmark':'fa-plus'} style={{marginRight:6}}/>{showForm ? t.cancel : t.bookAppointment}
        </button>
      </div>

      {showForm && (
        <div className="card" style={{marginBottom:'1.25rem',border:'1.5px solid #16a34a30'}}>
          <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'0.5rem',color:'#374151'}}>
            {editId ? 'Edit Appointment' : t.bookAppointment}
          </h4>
          <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:'0.75rem',background:'#f0fdf4',padding:'6px 10px',borderRadius:7,border:'1px solid #bbf7d0'}}>
            <I c="fa-circle-check" style={{color:'#16a34a',marginRight:5}}/>
            Your appointment will be saved to your dashboard. You'll see it listed below once booked.
            {' '}An email confirmation will also be sent if email is configured.
          </div>
          {msg && <div className="alert alert-error" style={{marginBottom:8}}>{msg}</div>}
          <div className="grid-2">
            <div className="form-group">
              <label className="form-label">{t.doctorName} *</label>
              <input className="form-input" value={form.doctor_name} onChange={set('doctor_name')} placeholder="e.g. Dr. Wambui Kamau"/>
            </div>
            <div className="form-group">
              <label className="form-label">{t.hospitalName}</label>
              <input className="form-input" value={form.hospital_name} onChange={set('hospital_name')}
                placeholder="e.g. Kenyatta National Hospital, Aga Khan…"/>
              <div style={{fontSize:'0.68rem',color:'#9ca3af',marginTop:2}}>Type any hospital name — see the Hospitals tab for the full Kenya list</div>
            </div>
            <div className="form-group">
              <label className="form-label">{t.date} *</label>
              <input type="date" className="form-input" value={form.appointment_date} onChange={set('appointment_date')} min={new Date().toISOString().split('T')[0]}/>
            </div>
            <div className="form-group">
              <label className="form-label">{t.time} *</label>
              <input type="time" className="form-input" value={form.appointment_time} onChange={set('appointment_time')}/>
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">{t.notes}</label>
            <textarea className="form-input" value={form.notes} onChange={set('notes')} rows={2} placeholder="Reason for visit, symptoms to discuss..."/>
          </div>
          <div style={{display:'flex',gap:8}}>
            <button className="btn btn-primary btn-sm" onClick={handleSubmit} disabled={saving}>
              {saving ? <><span className="spinner" style={{width:14,height:14}}/> Saving…</> : <><I c="fa-floppy-disk" style={{marginRight:4}}/>{t.save}</>}
            </button>
            <button className="btn btn-ghost btn-sm" onClick={()=>{setShowForm(false);setEditId(null);}}>{t.cancel}</button>
          </div>
        </div>
      )}

      {!appointments.length ? (
        <div style={{textAlign:'center',padding:'3rem',color:'#6b7280'}}>
          <I c="fa-calendar-xmark" style={{fontSize:'3rem',marginBottom:12,display:'block',color:'#d1d5db'}}/>
          <p>{t.noAppointments}</p>
        </div>
      ) : appointments.map(a => (
        <div key={a.id} className="card" style={{marginBottom:10,borderLeft:`3px solid ${statusColor[a.status]||'#e5e7eb'}`}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',flexWrap:'wrap',gap:8}}>
            <div>
              <div style={{fontWeight:700,fontSize:'0.9rem',color:'#111827',marginBottom:3}}>
                <I c="fa-user-doctor" style={{color:'#16a34a',marginRight:6}}/>{a.doctor_name}
              </div>
              {a.hospital_name && <div style={{fontSize:'0.8rem',color:'#6b7280',marginBottom:2}}><I c="fa-hospital" style={{marginRight:5}}/>{a.hospital_name}</div>}
              <div style={{fontSize:'0.82rem',color:'#374151',display:'flex',gap:12,flexWrap:'wrap',marginTop:4}}>
                <span><I c="fa-calendar" style={{marginRight:4,color:'#16a34a'}}/>{new Date(a.appointment_date+'T00:00:00').toLocaleDateString('en-KE',{weekday:'short',day:'numeric',month:'long',year:'numeric'})}</span>
                <span><I c="fa-clock" style={{marginRight:4,color:'#16a34a'}}/>{a.appointment_time}</span>
              </div>
              {a.notes && <div style={{fontSize:'0.78rem',color:'#6b7280',marginTop:4,fontStyle:'italic'}}>{a.notes}</div>}
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:4,alignItems:'flex-end'}}>
              <span style={{background:statusColor[a.status]||'#e5e7eb',color:'white',borderRadius:8,padding:'2px 10px',fontSize:'0.72rem',fontWeight:700,textTransform:'capitalize'}}>
                {t[a.status]||a.status}
              </span>
              <div style={{display:'flex',gap:4,marginTop:4}}>
                {a.status==='scheduled' && (
                  <button className="btn btn-ghost btn-sm" style={{fontSize:'0.7rem',padding:'3px 8px'}} onClick={()=>updateStatus(a.id,'completed')}>
                    <I c="fa-circle-check" style={{marginRight:3,color:'#16a34a'}}/>Done
                  </button>
                )}
                <button className="btn btn-ghost btn-sm" style={{fontSize:'0.7rem',padding:'3px 8px'}} onClick={()=>startEdit(a)}>
                  <I c="fa-pen" style={{marginRight:3}}/>Edit
                </button>
                <button className="btn btn-ghost btn-sm" style={{fontSize:'0.7rem',padding:'3px 8px',color:'#dc2626'}} onClick={()=>handleDelete(a.id)}>
                  <I c="fa-trash" style={{marginRight:3}}/>
                </button>
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

// ── Medications ───────────────────────────────────────────────────────────────
function MedicationsTab({ t }) {
  const [meds, setMeds] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ drug_name:'', dosage:'', frequency:'', start_date:'', end_date:'', notes:'' });
  const [saving, setSaving] = useState(false);
  const [interactions, setInteractions] = useState([]);
  const [checkingInter, setCheckingInter] = useState(false);
  const [msg, setMsg] = useState('');

  const FREQUENCIES = ['Once daily','Twice daily','Three times daily','Every 8 hours','Every 12 hours','Weekly','As needed'];

  const load = useCallback(() => {
    setLoading(true);
    api.get('/api/medications')
      .then(r => { setMeds(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);
  useEffect(() => { load(); }, [load]);

  const set = k => e => setForm({ ...form, [k]: e.target.value });

  const handleAdd = async () => {
    if (!form.drug_name) { setMsg('Drug name is required.'); return; }
    setSaving(true); setMsg('');
    try {
      await api.post('/api/medications', form);
      setShowForm(false); setForm({ drug_name:'', dosage:'', frequency:'', start_date:'', end_date:'', notes:'' });
      load();
    } catch { setMsg('Failed to add medication.'); }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Remove this medication?')) return;
    await api.delete(`/api/medications/${id}`);
    load();
  };

  const checkInteractions = async () => {
    setCheckingInter(true); setInteractions([]);
    try {
      const drugs = meds.map(m => m.drug_name);
      const res = await api.post('/api/check-interactions', { drugs });
      setInteractions(res.data.interactions || []);
    } catch { setInteractions([]); }
    setCheckingInter(false);
  };

  const sevColor = { severe:'#dc2626', moderate:'#d97706', mild:'#0891b2', beneficial:'#16a34a' };

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem',flexWrap:'wrap',gap:8}}>
        <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,color:'#374151',display:'flex',alignItems:'center',gap:8}}>
          <I c="fa-capsules" style={{color:'#16a34a'}}/>{t.medications} ({meds.length})
        </h3>
        <div style={{display:'flex',gap:6}}>
          {meds.length >= 2 && (
            <button className="btn btn-outline btn-sm" onClick={checkInteractions} disabled={checkingInter}>
              {checkingInter ? <><span className="spinner" style={{width:12,height:12}}/> Checking...</> : <><I c="fa-triangle-exclamation" style={{marginRight:4}}/>{t.checkInteractions}</>}
            </button>
          )}
          <button className="btn btn-primary btn-sm" onClick={()=>setShowForm(!showForm)}>
            <I c={showForm?'fa-xmark':'fa-plus'} style={{marginRight:6}}/>{showForm ? t.cancel : t.addMedication}
          </button>
        </div>
      </div>

      {/* Drug interaction results */}
      {interactions.length > 0 && (
        <div style={{marginBottom:'1rem'}}>
          {interactions.map((inter, i) => (
            <div key={i} className="alert" style={{background:`${sevColor[inter.severity]||'#6b7280'}10`,borderColor:`${sevColor[inter.severity]||'#6b7280'}40`,color:sevColor[inter.severity]||'#374151',marginBottom:6}}>
              <strong><I c={inter.severity==='beneficial'?'fa-circle-check':'fa-triangle-exclamation'} style={{marginRight:6}}/>{inter.drug1} + {inter.drug2}</strong>
              <span style={{marginLeft:8,background:sevColor[inter.severity]||'#6b7280',color:'white',borderRadius:4,padding:'1px 6px',fontSize:'0.68rem',fontWeight:700,textTransform:'capitalize'}}>{inter.severity}</span>
              <br/><span style={{fontSize:'0.82rem'}}>{inter.description}</span>
              <div style={{fontSize:'0.7rem',marginTop:2,opacity:0.7}}>Source: {inter.source}</div>
            </div>
          ))}
        </div>
      )}
      {interactions.length === 0 && checkingInter === false && meds.length >= 2 && (
        <div style={{display:'none'}}/>
      )}

      {showForm && (
        <div className="card" style={{marginBottom:'1.25rem',border:'1.5px solid #16a34a30'}}>
          <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'1rem',color:'#374151'}}>{t.addMedication}</h4>
          {msg && <div className="alert alert-error" style={{marginBottom:8}}>{msg}</div>}
          <div className="grid-2">
            <div className="form-group">
              <label className="form-label">{t.drugName} *</label>
              <input className="form-input" value={form.drug_name} onChange={set('drug_name')} placeholder="e.g. Ferrous Sulphate, Vitamin D3"/>
            </div>
            <div className="form-group">
              <label className="form-label">{t.dosage}</label>
              <input className="form-input" value={form.dosage} onChange={set('dosage')} placeholder="e.g. 200mg, 1 tablet"/>
            </div>
            <div className="form-group">
              <label className="form-label">{t.frequency}</label>
              <select className="form-input" value={form.frequency} onChange={set('frequency')}>
                <option value="">Select frequency...</option>
                {FREQUENCIES.map(f => <option key={f}>{f}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">{t.startDate}</label>
              <input type="date" className="form-input" value={form.start_date} onChange={set('start_date')}/>
            </div>
          </div>
          <div className="form-group">
            <label className="form-label">{t.notes}</label>
            <input className="form-input" value={form.notes} onChange={set('notes')} placeholder="Special instructions, e.g. take with food"/>
          </div>
          <div style={{display:'flex',gap:8}}>
            <button className="btn btn-primary btn-sm" onClick={handleAdd} disabled={saving}>
              {saving ? 'Saving...' : <><I c="fa-plus" style={{marginRight:4}}/>Add</>}
            </button>
            <button className="btn btn-ghost btn-sm" onClick={()=>setShowForm(false)}>{t.cancel}</button>
          </div>
        </div>
      )}

      {!meds.length ? (
        <div style={{textAlign:'center',padding:'3rem',color:'#6b7280'}}>
          <I c="fa-capsules" style={{fontSize:'3rem',marginBottom:12,display:'block',color:'#d1d5db'}}/>
          <p>{t.noMedications}</p>
          <div style={{marginTop:8,fontSize:'0.78rem',color:'#9ca3af'}}>Add your current medications and supplements to check for interactions.</div>
        </div>
      ) : (
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(260px,1fr))',gap:10}}>
          {meds.map(m => (
            <div key={m.id} className="card" style={{padding:'0.9rem'}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:6}}>
                <div style={{fontWeight:700,fontSize:'0.875rem',color:'#111827',flex:1}}>
                  <I c="fa-capsules" style={{color:'#16a34a',marginRight:6}}/>{m.drug_name}
                </div>
                <button onClick={()=>handleDelete(m.id)} style={{background:'none',border:'none',cursor:'pointer',color:'#9ca3af',padding:4,borderRadius:4}}>
                  <I c="fa-xmark" style={{fontSize:'0.8rem'}}/>
                </button>
              </div>
              {m.dosage && <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:2}}><I c="fa-scale-balanced" style={{marginRight:4}}/>{m.dosage}</div>}
              {m.frequency && <div style={{fontSize:'0.78rem',color:'#6b7280',marginBottom:2}}><I c="fa-clock" style={{marginRight:4}}/>{m.frequency}</div>}
              {m.start_date && <div style={{fontSize:'0.72rem',color:'#9ca3af',marginTop:4}}><I c="fa-calendar" style={{marginRight:4}}/>Started {m.start_date}</div>}
              {m.notes && <div style={{fontSize:'0.72rem',color:'#6b7280',marginTop:4,fontStyle:'italic'}}>{m.notes}</div>}
            </div>
          ))}
        </div>
      )}

      <div style={{marginTop:'1rem',padding:'0.75rem',background:'#fffbeb',borderRadius:10,border:'1px solid #fcd34d',fontSize:'0.78rem',color:'#92400e'}}>
        <I c="fa-triangle-exclamation" style={{marginRight:6,color:'#d97706'}}/>
        <strong>Important:</strong> Always inform your doctor of all medications and supplements. The interaction checker is a reference tool only.
      </div>
    </div>
  );
}

// ── Health Trends ─────────────────────────────────────────────────────────────
function HealthTrends({ t }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/api/trends')
      .then(r => { setData(r.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{textAlign:'center',padding:'3rem'}}><span className="spinner" style={{margin:'0 auto',display:'block'}}/></div>;
  if (!data) return <div className="alert alert-warning">Could not load trends. Is the backend running?</div>;

  const maxCount = Math.max(...(data.daily.map(d => d.count) || [1]), 1);

  return (
    <div>
      <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,marginBottom:'1.25rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
        <I c="fa-chart-line" style={{color:'#16a34a'}}/>{t.trends}
      </h3>

      {/* Summary stats */}
      <div className="grid-3" style={{marginBottom:'1.25rem'}}>
        {[
          { label:t.total, value:data.daily.reduce((s,d)=>s+d.count,0), color:'#16a34a', icon:'fa-stethoscope' },
          { label:'Days Active', value:data.daily.length, color:'#0891b2', icon:'fa-calendar-check' },
          { label:'Conditions Tracked', value:data.top_deficiencies.length, color:'#7c3aed', icon:'fa-brain' },
        ].map(s => (
          <div key={s.label} className="card" style={{textAlign:'center',padding:'1rem',border:`1px solid ${s.color}20`}}>
            <I c={s.icon} style={{fontSize:'1.4rem',color:s.color,marginBottom:6,display:'block'}}/>
            <div style={{fontSize:'1.8rem',fontWeight:800,fontFamily:'Fraunces,serif',color:s.color,lineHeight:1}}>{s.value}</div>
            <div style={{fontSize:'0.72rem',color:'#6b7280',marginTop:4}}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Daily activity bar chart */}
      <div className="card" style={{marginBottom:'1rem'}}>
        <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'1rem',color:'#374151'}}>{t.last30Days}</h4>
        {data.daily.length === 0 ? (
          <div style={{textAlign:'center',padding:'2rem',color:'#9ca3af',fontSize:'0.875rem'}}>No activity in the last 30 days. Use the AI Chat to get started!</div>
        ) : (
          <div style={{display:'flex',gap:3,alignItems:'flex-end',height:120,overflowX:'auto',paddingBottom:4}}>
            {data.daily.map(d => (
              <div key={d.day} style={{display:'flex',flexDirection:'column',alignItems:'center',gap:4,minWidth:28,flex:1}}>
                <div style={{fontSize:'0.6rem',color:'#9ca3af',fontWeight:700}}>{d.count}</div>
                <div title={`${d.day}: ${d.count} analysis`} style={{
                  width:'100%', minWidth:20,
                  height:`${Math.max((d.count/maxCount)*90, 8)}px`,
                  background:'linear-gradient(to top,#16a34a,#4ade80)',
                  borderRadius:'4px 4px 0 0',
                  transition:'height 0.3s'
                }}/>
                <div style={{fontSize:'0.55rem',color:'#9ca3af',whiteSpace:'nowrap',transform:'rotate(-45deg)',transformOrigin:'top left',marginTop:4}}>
                  {new Date(d.day).toLocaleDateString('en-KE',{month:'short',day:'numeric'})}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Top deficiencies */}
      {data.top_deficiencies.length > 0 && (
        <div className="card">
          <h4 style={{fontSize:'0.875rem',fontWeight:700,marginBottom:'1rem',color:'#374151'}}>{t.topConditions}</h4>
          {data.top_deficiencies.map((d, i) => (
            <div key={d.name} style={{display:'flex',alignItems:'center',gap:12,padding:'8px 0',borderBottom:i<data.top_deficiencies.length-1?'1px solid #f3f4f6':'none'}}>
              <span style={{fontSize:'0.75rem',fontWeight:800,color:'#9ca3af',width:20,textAlign:'center'}}>#{i+1}</span>
              <div style={{flex:1}}>
                <div style={{fontSize:'0.85rem',fontWeight:600,color:'#374151',marginBottom:2}}>{d.name}</div>
                <div style={{height:6,background:'#f3f4f6',borderRadius:3,overflow:'hidden'}}>
                  <div style={{height:'100%',background:'linear-gradient(to right,#16a34a,#4ade80)',width:`${(d.count/data.top_deficiencies[0].count)*100}%`,borderRadius:3}}/>
                </div>
              </div>
              <span style={{fontSize:'0.8rem',fontWeight:700,color:'#16a34a',minWidth:28,textAlign:'right'}}>{d.count}×</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// ── Profile ───────────────────────────────────────────────────────────────────
function Profile({ t, darkMode, setDarkMode, lang, setLang }) {
  const { user, login, token, logout } = useAuth();
  const [form, setForm] = useState({
    name: user?.name||'', age: user?.age||'', blood_group: user?.blood_group||'',
    allergies: user?.allergies||'', chronic_conditions: user?.chronic_conditions||'',
    emergency_contact: user?.emergency_contact||'', emergency_phone: user?.emergency_phone||'',
    language: lang, dark_mode: darkMode
  });
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');
  const BLOOD_GROUPS = ['A+','A-','B+','B-','AB+','AB-','O+','O-'];
  const set = k => e => setForm({...form,[k]:e.target.value});

  const handleSave = async e => {
    e.preventDefault(); setSaving(true); setMsg('');
    try {
      const res = await api.put('/api/profile', { ...form, dark_mode: darkMode, language: lang });
      login(res.data, token);
      setMsg('Profile updated!');
    } catch { setMsg('Failed to save. Is the backend running?'); }
    setSaving(false);
  };

  return (
    <div style={{maxWidth:500}}>
      <h3 style={{fontSize:'1rem',fontFamily:'Outfit,sans-serif',fontWeight:700,marginBottom:'1rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
        <I c="fa-user-circle" style={{color:'#16a34a'}}/>{t.profile}
      </h3>

      {/* Preferences */}
      <div className="card" style={{marginBottom:'1rem'}}>
        <div style={{fontWeight:700,fontSize:'0.8rem',color:'#374151',marginBottom:'0.75rem',textTransform:'uppercase',letterSpacing:'0.05em'}}>Preferences</div>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'8px 0',borderBottom:'1px solid #f3f4f6'}}>
          <span style={{fontSize:'0.875rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
            <I c="fa-moon" style={{color:'#7c3aed'}}/>{t.darkMode}
          </span>
          <button onClick={()=>setDarkMode(!darkMode)} style={{width:44,height:24,borderRadius:12,background:darkMode?'#16a34a':'#d1d5db',border:'none',cursor:'pointer',position:'relative',transition:'background 0.2s'}}>
            <span style={{position:'absolute',top:2,left:darkMode?22:2,width:20,height:20,background:'white',borderRadius:'50%',transition:'left 0.2s',boxShadow:'0 1px 4px rgba(0,0,0,0.2)'}}/>
          </button>
        </div>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'8px 0'}}>
          <span style={{fontSize:'0.875rem',color:'#374151',display:'flex',alignItems:'center',gap:8}}>
            <I c="fa-language" style={{color:'#0891b2'}}/>{t.language}
          </span>
          <div style={{display:'flex',gap:4}}>
            {['en','sw'].map(l => (
              <button key={l} onClick={()=>setLang(l)}
                style={{padding:'4px 12px',borderRadius:6,border:'1.5px solid',borderColor:lang===l?'#16a34a':'#e5e7eb',background:lang===l?'#16a34a':'transparent',color:lang===l?'white':'#374151',cursor:'pointer',fontSize:'0.8rem',fontWeight:600}}>
                {l==='en'?'English':'Kiswahili'}
              </button>
            ))}
          </div>
        </div>
      </div>

      {msg && <div className={`alert ${msg.includes('updated')?'alert-success':'alert-error'}`}>{msg}</div>}
      <form onSubmit={handleSave} className="card">
        <div className="form-group">
          <label className="form-label"><I c="fa-user" style={{marginRight:6,color:'#6b7280'}}/>Full Name</label>
          <input className="form-input" value={form.name} onChange={set('name')} required/>
        </div>
        <div className="grid-2">
          <div className="form-group">
            <label className="form-label"><I c="fa-calendar" style={{marginRight:6,color:'#6b7280'}}/>Age</label>
            <input type="number" className="form-input" value={form.age} onChange={set('age')} min="1" max="120"/>
