        <button type="submit" className="btn btn-primary" disabled={saving} style={{width:'100%',justifyContent:'center',padding:'0.7rem'}}>
          {saving ? <><span className="spinner" style={{width:16,height:16}}/> Saving…</> : <><I c="fa-floppy-disk" style={{marginRight:6}}/>{t.saveProfile}</>}
        </button>
      </form>

      {/* ── Danger Zone ── */}
      <div className="card" style={{marginTop:'1rem',border:'1.5px solid #fca5a5'}}>
        <div style={{fontWeight:700,fontSize:'0.8rem',color:'#dc2626',textTransform:'uppercase',letterSpacing:'0.05em',marginBottom:'0.75rem',display:'flex',alignItems:'center',gap:6}}>
          <I c="fa-skull-crossbones"/>Danger Zone
        </div>
        <DangerAction
          label="Delete All History"
          desc="Permanently removes all your analysis history from the database."
          btnLabel="Delete History"
          icon="fa-trash-can"
          onConfirm={async () => {
            await api.delete('/api/history');
            setMsg('All history deleted.');
          }}
          confirmText="DELETE HISTORY"
        />
        <hr style={{border:'none',borderTop:'1px solid #fca5a580',margin:'0.75rem 0'}}/>
        <DangerAction
          label="Delete My Account"
          desc="Permanently deletes your account, all analyses, appointments, medications and data. This cannot be undone."
          btnLabel="Delete Account"
          icon="fa-user-slash"
          requirePassword
          onConfirm={async (pwd) => {
            await api.delete('/api/account', { data: { password: pwd } });
            logout();
          }}
          confirmText="DELETE MY ACCOUNT"
        />
      </div>
    </div>
  );
}

// ── Danger Action helper ───────────────────────────────────────────────────────
function DangerAction({ label, desc, btnLabel, icon, onConfirm, confirmText, requirePassword }) {
  const [open, setOpen] = useState(false);
  const [typed, setTyped] = useState('');
  const [pwd, setPwd]   = useState('');
  const [busy, setBusy] = useState(false);
  const [err, setErr]   = useState('');

  const doIt = async () => {
    setBusy(true); setErr('');
    try {
      await onConfirm(pwd);
      setOpen(false);
    } catch (e) {
      setErr(e.response?.data?.error || 'Operation failed.');
    }
    setBusy(false);
  };

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:10}}>
        <div>
          <div style={{fontWeight:600,fontSize:'0.875rem'}}>{label}</div>
          <div style={{fontSize:'0.75rem',color:'#6b7280',marginTop:2}}>{desc}</div>
        </div>
        <button onClick={()=>{setOpen(!open);setTyped('');setPwd('');setErr('');}}
          className="btn btn-sm" style={{background:'#fef2f2',color:'#dc2626',border:'1px solid #fca5a5',flexShrink:0,whiteSpace:'nowrap'}}>
          <I c={icon} style={{marginRight:5}}/>{btnLabel}
        </button>
      </div>
      {open && (
        <div style={{marginTop:10,background:'#fff5f5',border:'1px solid #fca5a5',borderRadius:8,padding:'0.75rem'}}>
          <div style={{fontSize:'0.78rem',color:'#dc2626',marginBottom:6}}>
            Type <strong>{confirmText}</strong> to confirm:
          </div>
          <input className="form-input" value={typed} onChange={e=>setTyped(e.target.value)}
            placeholder={confirmText} style={{marginBottom:6,borderColor:'#fca5a5'}}/>
          {requirePassword && (
            <input type="password" className="form-input" value={pwd} onChange={e=>setPwd(e.target.value)}
              placeholder="Enter your password to confirm" style={{marginBottom:6,borderColor:'#fca5a5'}}/>
          )}
          {err && <div style={{fontSize:'0.75rem',color:'#dc2626',marginBottom:6}}>{err}</div>}
          <div style={{display:'flex',gap:6}}>
            <button onClick={doIt}
              disabled={typed !== confirmText || busy || (requirePassword && !pwd)}
              className="btn btn-sm" style={{background:'#dc2626',color:'white',border:'none',opacity:typed!==confirmText?0.5:1}}>
              {busy ? <span className="spinner" style={{width:13,height:13}}/> : <><I c={icon} style={{marginRight:4}}/>{btnLabel}</>}
            </button>
            <button onClick={()=>setOpen(false)} className="btn btn-ghost btn-sm">Cancel</button>
          </div>
        </div>
      )}
    </div>
  );
}

// ── SOS Modal ─────────────────────────────────────────────────────────────────
function SOSModal({ onClose, user }) {
  const [sending, setSending] = useState(false);
  const [result, setResult] = useState(null);
  const [loc, setLoc] = useState(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        pos => setLoc({ lat: pos.coords.latitude, lon: pos.coords.longitude }),
        () => {}
      );
    }
  }, []);

  const sendSOS = async () => {
    setSending(true);
    try {
      const res = await api.post('/api/sos', loc || {});
      setResult(res.data);
    } catch { setResult({ error: 'SOS failed. Please call 999 directly.' }); }
    setSending(false);
  };

  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',zIndex:2000,display:'flex',alignItems:'center',justifyContent:'center',padding:'1rem'}}
         onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div style={{background:'white',borderRadius:16,padding:'1.5rem',maxWidth:420,width:'100%',boxShadow:'0 20px 60px rgba(0,0,0,0.3)'}}>
        <div style={{textAlign:'center',marginBottom:'1.25rem'}}>
          <div style={{width:60,height:60,borderRadius:'50%',background:'#fef2f2',border:'3px solid #dc2626',display:'flex',alignItems:'center',justifyContent:'center',margin:'0 auto 12px'}}>
            <I c="fa-circle-exclamation" style={{fontSize:'1.8rem',color:'#dc2626'}}/>
          </div>
          <h2 style={{fontFamily:'Fraunces,serif',color:'#dc2626',fontSize:'1.4rem',marginBottom:4}}>Emergency SOS</h2>
          <p style={{fontSize:'0.875rem',color:'#6b7280'}}>This will alert your emergency contact and show nearest hospitals.</p>
        </div>

        {/* Emergency numbers */}
        <div style={{background:'#fef2f2',borderRadius:10,padding:'0.75rem',marginBottom:'1rem'}}>
          <div style={{fontWeight:700,fontSize:'0.8rem',color:'#dc2626',marginBottom:6}}>Emergency Numbers — Call Now</div>
          {[['Police / Ambulance', '999'], ['Ambulance (alt)', '1199'], ['Red Cross', '0800 720 990'], ['Toll-Free Health', '0800 723 253']].map(([label, num]) => (
            <div key={num} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'4px 0',borderBottom:'1px solid #fca5a5'}}>
              <span style={{fontSize:'0.82rem',color:'#374151'}}>{label}</span>
              <a href={`tel:${num.replace(/\s/g,'')}`} style={{fontWeight:800,fontSize:'0.95rem',color:'#dc2626',textDecoration:'none'}}>{num}</a>
            </div>
          ))}
        </div>

        {loc && <div style={{fontSize:'0.78rem',color:'#16a34a',marginBottom:'0.75rem',textAlign:'center'}}><I c="fa-location-dot" style={{marginRight:4}}/>Location detected — will be included in alert</div>}

        {result ? (
          result.error ? (
            <div className="alert alert-error">{result.error}</div>
          ) : (
            <div>
              <div className="alert alert-success"><I c="fa-circle-check" style={{marginRight:6}}/>Alert sent! Emergency contacts notified.</div>
              {result.nearby_hospitals?.length > 0 && (
                <div style={{marginTop:'0.75rem'}}>
                  <div style={{fontWeight:700,fontSize:'0.8rem',color:'#374151',marginBottom:6}}>Nearest Emergency Hospitals:</div>
                  {result.nearby_hospitals.map(h => (
                    <div key={h.name} style={{padding:'6px 10px',background:'#f0fdf4',borderRadius:8,marginBottom:6,fontSize:'0.82rem'}}>
                      <div style={{fontWeight:700,color:'#15803d'}}>{h.name}</div>
                      <div style={{color:'#374151'}}>{h.distance_km} km · <a href={`tel:${h.phone}`} style={{color:'#dc2626',fontWeight:700}}>{h.phone}</a></div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )
        ) : (
          <div style={{display:'flex',gap:8}}>
            <button className="btn btn-danger" style={{flex:2,justifyContent:'center'}} onClick={sendSOS} disabled={sending}>
              {sending ? <><span className="spinner" style={{width:16,height:16}}/> Sending...</> : <><I c="fa-bell" style={{marginRight:6}}/>Send SOS Alert</>}
            </button>
            <button className="btn btn-ghost" style={{flex:1,justifyContent:'center'}} onClick={onClose}>Close</button>
          </div>
        )}
        {result && <button className="btn btn-ghost" style={{width:'100%',justifyContent:'center',marginTop:8}} onClick={onClose}>Close</button>}
      </div>
    </div>
  );
}

