          <div>
            <h2 style={{fontSize:'1.4rem',marginBottom:2,display:'flex',alignItems:'center',gap:8,color:darkMode?'#f9fafb':'#111827'}}>
              <I c="fa-hand-wave" style={{color:'#d97706'}}/>{t.hello}, {user?.name?.split(' ')[0]}
            </h2>
            <p style={{color:darkMode?'#9ca3af':'#6b7280',fontSize:'0.875rem'}}>{t.dashboard}</p>
          </div>
          <div style={{display:'flex',gap:6,flexWrap:'wrap',alignItems:'center'}}>
            {user?.blood_group && (
              <span style={{background:'#fef2f2',color:'#dc2626',border:'1px solid #fca5a5',borderRadius:8,padding:'4px 10px',fontSize:'0.75rem',fontWeight:700,display:'flex',alignItems:'center',gap:5}}>
                <I c="fa-droplet"/>{user.blood_group}
              </span>
            )}
            {/* Dark mode quick toggle */}
            <button onClick={()=>setDarkMode(!darkMode)} title={t.darkMode}
              style={{background:darkMode?'#374151':'#f3f4f6',border:'1px solid #e5e7eb',borderRadius:8,padding:'6px 10px',cursor:'pointer',color:darkMode?'#f9fafb':'#374151',fontSize:'0.85rem'}}>
              <I c={darkMode?'fa-sun':'fa-moon'}/>
            </button>
            {/* Language toggle */}
            <button onClick={()=>setLang(lang==='en'?'sw':'en')} title={t.language}
              style={{background:'#f3f4f6',border:'1px solid #e5e7eb',borderRadius:8,padding:'5px 10px',cursor:'pointer',color:'#374151',fontSize:'0.78rem',fontWeight:700}}>
              <I c="fa-language" style={{marginRight:4}}/>{lang.toUpperCase()}
            </button>
            {/* SOS Button */}
            <button onClick={()=>setShowSOS(true)} className="btn btn-sm"
              style={{background:'#dc2626',color:'white',border:'none',animation:'sosPulse 2s ease-in-out infinite'}}>
              <I c="fa-circle-exclamation" style={{marginRight:5}}/>SOS
            </button>
          </div>
        </div>

        {/* Tabs */}
        <div className="tabs">
          {TABS.map(tab_info => (
            <button key={tab_info.key} className={`tab ${tab===tab_info.key?'active':''}`} onClick={()=>setTab(tab_info.key)}>
              <I c={tab_info.icon} style={{marginRight:6}}/>{t[tab_info.labelKey]}
            </button>
          ))}
        </div>

        {tab==='chat'         && <Chatbot user={user} lang={lang}/>}
        {tab==='history'      && <History t={t} lang={lang}/>}
        {tab==='appointments' && <AppointmentsTab t={t}/>}
        {tab==='medications'  && <MedicationsTab t={t}/>}
        {tab==='trends'       && <HealthTrends t={t}/>}
        {tab==='hospitals'    && <HospitalMap/>}
        {tab==='profile'      && <Profile t={t} darkMode={darkMode} setDarkMode={setDarkMode} lang={lang} setLang={setLang}/>}

        {showSOS && <SOSModal onClose={()=>setShowSOS(false)} user={user}/>}
      </div>
      <style>{`
        @keyframes sosPulse { 0%,100%{box-shadow:0 0 0 0 rgba(220,38,38,0.4)} 50%{box-shadow:0 0 0 8px rgba(220,38,38,0)} }
      `}</style>
    </div>
  );
}
